// SendTypingIndicator is the resolver for the sendTypingIndicator field.
func (r *mutationResolver) SendTypingIndicator(ctx context.Context, input model.SendTypingIndicatorInput) (bool, error) {
	user, err := requireAuth(ctx)
	if err != nil {
		return false, err
	}
	kind, err := r.resolveRoomKind(ctx, input.RoomID)
	if err != nil {
		return false, err
	}

	// Authorization: check room membership
	isMember, err := r.core.RoomMembershipExists(ctx, kind, user.Id, input.RoomID)
	if err != nil {
		return false, err
	}
	if !isMember {
		return false, core.ErrNotRoomMember
	}

	// Publish the typing indicator (live-only event, no permission check beyond membership)
	if err := r.core.PublishTypingIndicator(ctx, user.Id, kind, input.RoomID, input.ThreadRootEventID); err != nil {
		return false, err
	}

	return true, nil
}

// DeleteMessage is the resolver for the deleteMessage field.
func (r *mutationResolver) DeleteMessage(ctx context.Context, input model.DeleteMessageInput) (bool, error) {
	user, err := requireAuth(ctx)
	if err != nil {
		return false, err
	}
	kind, err := r.resolveRoomKind(ctx, input.RoomID)
	if err != nil {
		return false, err
	}

	// Authorization: check room membership
	isMember, err := r.core.RoomMembershipExists(ctx, kind, user.Id, input.RoomID)
	if err != nil {
		return false, err
	}
	if !isMember {
		return false, core.ErrNotRoomMember
	}

	// Resolve event ID to internal body key
	messageBodyKey, err := r.resolveMessageBodyKey(ctx, kind, input.RoomID, input.EventID)
	if err != nil {
		return false, err
	}

	// Authorization: check ownership and permissions
	authorID, err := r.core.GetMessageAuthorID(ctx, kind, messageBodyKey)
	if err != nil {
		return false, err
	}
	if authorID == "" {
		// Message already deleted, nothing to do
		return true, nil
	}

	if user.Id != authorID {
		// Non-author deleting: check message.manage permission AND
		// strict-outrank on the author. The rank check prevents a
		// moderator from deleting messages of higher-ranked users
		// (admins, owners) — see requireOutranksAuthor.
		can, err := r.core.CanManageOthersMessage(ctx, user.Id, kind, input.RoomID)
		if err != nil {
			return false, err
		}
		if !can {
			return false, core.ErrPermissionDenied
		}
		if err := r.requireOutranksAuthor(ctx, user.Id, authorID); err != nil {
			return false, err
		}
	}
	// Authors deleting their own messages: always allowed (subject to
	// membership, which we already checked above).

	if err := r.core.DeleteMessage(ctx, user.Id, kind, input.RoomID, messageBodyKey); err != nil {
		return false, err
	}

	return true, nil
}

// UpdateMessage is the resolver for the updateMessage field.
func (r *mutationResolver) UpdateMessage(ctx context.Context, input model.UpdateMessageInput) (bool, error) {
	user, err := requireAuth(ctx)
	if err != nil {
		return false, err
	}
	kind, err := r.resolveRoomKind(ctx, input.RoomID)
	if err != nil {
		return false, err
	}

	// Authorization: check room membership
	isMember, err := r.core.RoomMembershipExists(ctx, kind, user.Id, input.RoomID)
	if err != nil {
		return false, err
	}
	if !isMember {
		return false, core.ErrNotRoomMember
	}

	// Resolve event ID to internal body key
	messageBodyKey, err := r.resolveMessageBodyKey(ctx, kind, input.RoomID, input.EventID)
	if err != nil {
		return false, err
	}

	// Get the message to determine authorship
	messageBody, err := r.core.GetFullMessageBody(ctx, kind, messageBodyKey)
	if err != nil {
		return false, err
	}
	if messageBody == nil {
		return false, core.ErrMessageNotFound
	}

	// Authorization: authors editing their own messages are always allowed
	// (the edit window is enforced in Core.EditMessage). Non-author edits
	// require message.manage AND strict-outrank on the author — the rank
	// check prevents a moderator from editing messages of higher-ranked
	// users (admins, owners).
	if messageBody.AuthorId != user.Id {
		can, err := r.core.CanManageOthersMessage(ctx, user.Id, kind, input.RoomID)
		if err != nil {
			return false, err
		}
		if !can {
			return false, core.ErrPermissionDenied
		}
		if err := r.requireOutranksAuthor(ctx, user.Id, messageBody.AuthorId); err != nil {
			return false, err
		}
	}

	if err := r.core.EditMessage(ctx, user.Id, kind, input.RoomID, messageBodyKey, input.Body); err != nil {
		return false, err
	}

	return true, nil
}

