// UpdateProfile is the resolver for the updateProfile field.
func (r *mutationResolver) UpdateProfile(ctx context.Context, input model.UpdateProfileInput) (*corev1.User, error) {
	if _, err := r.requireSelfOrUserAdminTarget(ctx, input.UserID); err != nil {
		return nil, err
	}

	if input.DisplayName == nil && input.Login == nil {
		return nil, fmt.Errorf("at least one of displayName or login must be provided")
	}

	var updatedUser *corev1.User
	var err error

	if input.DisplayName != nil {
		updatedUser, err = r.core.UpdateUserDisplayName(ctx, input.UserID, *input.DisplayName)
		if err != nil {
			return nil, err
		}
	}

	if input.Login != nil {
		updatedUser, err = r.core.UpdateUserLogin(ctx, input.UserID, *input.Login)
		if err != nil {
			return nil, err
		}
	}

	return updatedUser, nil
}

// UploadAvatar is the resolver for the uploadAvatar field.
func (r *mutationResolver) UploadAvatar(ctx context.Context, input model.UploadAvatarInput) (*corev1.User, error) {
	if _, err := r.requireSelfOrUserAdminTarget(ctx, input.UserID); err != nil {
		return nil, err
	}

	asset, err := r.core.UploadUserAvatar(ctx, input.UserID, input.File.File)
	if err != nil {
		return nil, fmt.Errorf("failed to upload avatar: %w", err)
	}

	if err := r.core.SetUserAvatar(ctx, input.UserID, asset); err != nil {
		r.core.CleanupAsset(ctx, core.DeprecatedAssetFromAsset(asset))
		return nil, fmt.Errorf("failed to save avatar: %w", err)
	}

	return r.core.GetUser(ctx, input.UserID)
}

// DeleteAvatar is the resolver for the deleteAvatar field.
func (r *mutationResolver) DeleteAvatar(ctx context.Context, input model.DeleteAvatarInput) (*corev1.User, error) {
	if _, err := r.requireSelfOrUserAdminTarget(ctx, input.UserID); err != nil {
		return nil, err
	}

	if err := r.core.DeleteUserAvatar(ctx, input.UserID); err != nil {
		return nil, fmt.Errorf("failed to delete avatar: %w", err)
	}

	return r.core.GetUser(ctx, input.UserID)
}

// RequestAccountDeletion is the resolver for the requestAccountDeletion field.
func (r *mutationResolver) RequestAccountDeletion(ctx context.Context) (string, error) {
	user, err := requireAuth(ctx)
	if err != nil {
		return "", err
	}

	// Self only - no additional authorization needed
	return r.core.CreateAccountDeletionToken(ctx, user.Id)
}

// DeleteMyAccount is the resolver for the deleteMyAccount field.
func (r *mutationResolver) DeleteMyAccount(ctx context.Context, input model.DeleteMyAccountInput) (bool, error) {
	user, err := requireAuth(ctx)
	if err != nil {
		return false, err
	}

	// Validate the confirmation token (XSS protection)
	if err := r.core.ValidateAccountDeletionToken(ctx, input.ConfirmationToken, user.Id); err != nil {
		return false, err
	}

	// Self-deletion
	if err := r.core.DeleteUser(ctx, user.Id, user.Id); err != nil {
		return false, err
	}

	return true, nil
}

// Mutation returns MutationResolver implementation.
func (r *Resolver) Mutation() MutationResolver { return &mutationResolver{r} }

type mutationResolver struct{ *Resolver }
